example.code:
// Create a collider using defaults from ConeProceduralModel
var collider = ConeCollider.Create(null);

// Or create a collider with explicit radius (X) and height (Y); Z is unused
var collider2 = ConeCollider.Create(new Vector3(0.5f, 2.0f, 0f));

// Create a collider using defaults from TeapotProceduralModel
var collider = TeapotCollider.Create(null);

// Or create a collider with an explicit size (scale)
var collider2 = TeapotCollider.Create(0.75f);

// Create a collider using defaults from TorusProceduralModel
var collider = TorusCollider.Create(null, null);

// Or create a collider with explicit major and minor radii
var collider2 = TorusCollider.Create(majorRadius: 1.25f, minorRadius: 0.35f);

// Create a collider using defaults from TriangularPrismProceduralModel
var collider = TriangularPrismCollider.Create(null);

// Or create a collider with explicit base width (X), height (Y), and depth (Z)
var collider2 = TriangularPrismCollider.Create(new Vector3(1.0f, 1.0f, 2.0f));
